  const micInputPreGainNodeRef = useRef(null);
  const micInputSaturationNodeRef = useRef(null);
  const masterGlueCompressorRef = useRef(null);
  const masterGlueDryGainRef = useRef(null);
  const masterGlueWetGainRef = useRef(null);
  const masterLimiterRef = useRef(null);
  const limiterAnalyserRef = useRef(null);

  const makeNeveSaturationCurve = (amount) => {
    const k = (amount / 100) * 8.0; // scale from 0 to 8 for rich saturation harmonics
    const n_samples = 44100;
    const curve = new Float32Array(n_samples);
    for (let i = 0; i < n_samples; ++i) {
      const x = (i * 2) / (n_samples - 1) - 1;
      if (k === 0) {
        curve[i] = x;
      } else {
        curve[i] = ((1 + k) * x) / (1 + k * Math.abs(x));
      }
    }
    return curve;
  };

  const updateLiveInputSaturation = () => {
    const ctx = audioCtxRef.current;
    if (!ctx) return;
    const now = ctx.currentTime;
    
    if (micInputPreGainNodeRef.current) {
      const driveFactor = 1.0 + (inputGainSatRef.current / 100) * 3.0;
      micInputPreGainNodeRef.current.gain.setValueAtTime(driveFactor, now);
    }
    
    if (micInputSaturationNodeRef.current) {
      micInputSaturationNodeRef.current.curve = makeNeveSaturationCurve(inputGainSatRef.current);
    }
    
    if (micInputGainNodeRef.current) {
      const scaleDown = 1.0 + (inputGainSatRef.current / 100) * 1.5;
      const finalGain = recordingInputGainRef.current / scaleDown;
      micInputGainNodeRef.current.gain.setValueAtTime(finalGain, now);
    }
  };

  const updateGlueMixDSP = () => {
    const ctx = audioCtxRef.current;
    if (!ctx) return;
    const now = ctx.currentTime;
    const mix = glueMixRef.current / 100;
    
    if (masterGlueDryGainRef.current) {
      masterGlueDryGainRef.current.gain.setValueAtTime(1.0 - mix, now);
    }
    if (masterGlueWetGainRef.current) {
      masterGlueWetGainRef.current.gain.setValueAtTime(mix, now);
    }
  };

  const updateLimiterActiveDSP = () => {
    const ctx = audioCtxRef.current;
    if (!ctx) return;
    const active = masterLimiterActiveRef.current;
    if (!masterGlueDryGainRef.current || !masterGlueWetGainRef.current || !masterLimiterRef.current || !limiterAnalyserRef.current) return;

    try {
      masterGlueDryGainRef.current.disconnect();
      masterGlueWetGainRef.current.disconnect();
      masterLimiterRef.current.disconnect();
    } catch (e) {
      // ignore
    }

    if (active) {
      masterGlueDryGainRef.current.connect(masterLimiterRef.current);
      masterGlueWetGainRef.current.connect(masterLimiterRef.current);
      masterLimiterRef.current.connect(limiterAnalyserRef.current);
    } else {
      masterGlueDryGainRef.current.connect(limiterAnalyserRef.current);
      masterGlueWetGainRef.current.connect(limiterAnalyserRef.current);
    }
  };

  const triggerDuckerSidechain = (targetTime = null) => {
    const ctx = audioCtxRef.current;
    if (!ctx) return;
    const duckerAmt = duckerAmountRef.current;
    if (duckerAmt <= 0) return;

    const now = ctx.currentTime;
    const tStart = targetTime !== null ? targetTime : now;
    const reduction = (duckerAmt / 100) * 0.85; // up to 85% volume ducking
    const recoveryTime = 0.15 + (duckerAmt / 100) * 0.25; // 150ms to 400ms recovery time

    activeVoicesRef.current.forEach((voicesList, key) => {
      // Duck only synthesizer / keyboard voices (keys that are numeric, i.e., MIDI notes)
      const isSynthVoice = typeof key === 'number' || (typeof key === 'string' && !key.startsWith('perf-') && !key.startsWith('preview-'));
      if (!isSynthVoice) return;

      voicesList.forEach(voice => {
        if (voice && voice.voiceOutGain) {
          const param = voice.voiceOutGain.gain;
          // Cancel scheduled volume points after tStart
          param.cancelScheduledValues(tStart);
          
          const normalVol = voice.normalVolume !== undefined ? voice.normalVolume : 0.5;
          const duckedVol = normalVol * (1.0 - reduction);

          // Phase-accurate ducking envelope
          param.setValueAtTime(normalVol, tStart);
          param.linearRampToValueAtTime(duckedVol, tStart + 0.012); // quick 12ms attack
          param.setTargetAtTime(normalVol, tStart + 0.012, recoveryTime / 3);
        }
      });
    });
  };

