        if (isLoopB) {
          oscB.loopStart = loopStartB;
          oscB.loopEnd = loopEndB;
        }
        voiceObj.origLoopStartB = loopStartB;
        voiceObj.origLoopEndB = loopEndB;
        voiceObj.isLoopB = isLoopB;

