        gainB.gain.linearRampToValueAtTime(vca.breakLevel * vcaEnvAmt * gainBVol, dTime);
        gainB.gain.linearRampToValueAtTime(vca.sustainLevel * vcaEnvAmt * gainBVol, sTime);
