                  background: deckAKeyLock ? '#00f3ff' : 'rgba(0, 243, 255, 0.05)',
                  color: deckAKeyLock ? '#000' : '#00f3ff',
                  border: '1px solid rgba(0, 243, 255, 0.3)',
                  borderRadius: '2px',
                  cursor: 'pointer',
                  fontWeight: 'bold',
                  boxShadow: deckAKeyLock ? '0 0 6px #00f3ff' : 'none',
