// ==========================================
// 11. COMPUTER KEYBOARD TRIGGER LISTENER
// ==========================================

function KeyboardTrigger({ playVoice, stopVoice }) {
  useEffect(() => {
    // Map home-row keyboard layout to musical white/black scale notes
    const keysMap = {
      'a': 60, // C4
      'w': 61, // C#
      's': 62, // D
      'e': 63, // D#
      'd': 64, // E
      'f': 65, // F
      't': 66, // F#
      'g': 67, // G
      'y': 68, // G#
      'h': 69, // A
      'u': 70, // A#
      'j': 71, // B
      'k': 72, // C5
    };

    const keysActive = new Set();

    const handleKeyDown = (e) => {
      if (e.repeat) return;
      const note = keysMap[e.key.toLowerCase()];
      if (note && !keysActive.has(note)) {
        keysActive.add(note);
        playVoice(note, 100);
      }
    };

    const handleKeyUp = (e) => {
      const note = keysMap[e.key.toLowerCase()];
      if (note && keysActive.has(note)) {
        keysActive.delete(note);
        stopVoice(note);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    window.addEventListener('keyup', handleKeyUp);

    return () => {
      window.removeEventListener('keydown', handleKeyDown);
      window.removeEventListener('keyup', handleKeyUp);
    };
  }, [playVoice, stopVoice]);

  return null;
}

